<?php/** * Updates Module custom post type */add_action('init', 'faqs_post_type_register');function faqs_post_type_register() {	register_post_type( 'faqs' ,						array(							'label' => 'FAQS',							'singular_label' => 'FAQS',							'public' => true,							'show_ui' => true,							//'menu_icon' => get_stylesheet_directory_uri() . '/images/testimonials-icon.png', 							'capability_type' => 'post',							'hierarchical' => false,							'rewrite' => true,							'show_in_nav_faqs' => true,							'supports' => array('title','thumbnail' ,'editor')						)					);	add_filter('manage_edit-faqs_columns', 'faqs_edit_columns');	function faqs_edit_columns($columns){		$columns = array(			'cb' 	=> '<input type="checkbox" />',			'title' => 'faqs',			'author'=> 'Author',			'date'	=>'Date'		);		return $columns;	}}?>